import{_ as e,o as i,c as s,ao as a}from"./chunks/framework.C2uOknPB.js";const g=JSON.parse('{"title":"The pt CLI","description":"","frontmatter":{},"headers":[],"relativePath":"guide/cli.md","filePath":"guide/cli.md","lastUpdated":null}'),l={name:"guide/cli.md"};function n(d,t,h,o,p,r){return i(),s("div",null,[...t[0]||(t[0]=[a(`<h1 id="The-pt-CLI" tabindex="-1">The <code>pt</code> CLI <a class="header-anchor" href="#The-pt-CLI" aria-label="Permalink to &quot;The \`pt\` CLI {#The-pt-CLI}&quot;">​</a></h1><p><code>pt</code> is ParselTongue&#39;s command-line interface. It wraps <a href="/ParselTongue.jl/dev/reference/api#Building"><code>build_extension</code></a>, <a href="/ParselTongue.jl/dev/reference/api#Building"><code>build_wheel</code></a>, and the startup benchmark so you can compile extensions and wheels without writing a Julia script or starting a REPL each time.</p><p>There are three ways to run it, from quickest-to-set-up to fastest-to-run.</p><h2 id="Running-pt" tabindex="-1">Running <code>pt</code> <a class="header-anchor" href="#Running-pt" aria-label="Permalink to &quot;Running \`pt\` {#Running-pt}&quot;">​</a></h2><h3 id="1.-Interpreted-no-setup" tabindex="-1">1. Interpreted (no setup) <a class="header-anchor" href="#1.-Interpreted-no-setup" aria-label="Permalink to &quot;1. Interpreted (no setup) {#1.-Interpreted-no-setup}&quot;">​</a></h3><p>Run the CLI straight from the source tree. This starts a fresh Julia session each time (a few seconds of latency) but needs no build step:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/pt.jl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/mathx/mathx.jl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --outdir=build</span></span></code></pre></div><h3 id="2.-As-a-Pkg-App-recommended" tabindex="-1">2. As a Pkg App (recommended) <a class="header-anchor" href="#2.-As-a-Pkg-App-recommended" aria-label="Permalink to &quot;2. As a Pkg App (recommended) {#2.-As-a-Pkg-App-recommended}&quot;">​</a></h3><p>On Julia ≥ 1.12, install <code>pt</code> as a <a href="https://pkgdocs.julialang.org/v1/apps/" target="_blank" rel="noreferrer">Pkg App</a>. This puts a <code>pt</code> shim on your <code>PATH</code> (at <code>~/.julia/bin/pt</code>) that runs <code>julia -m ParselTongue</code>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.Apps.develop(path=&quot;.&quot;)&#39;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># ensure ~/.julia/bin is on your PATH, then:</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/mathx/mathx.jl</span></span></code></pre></div><h3 id="3.-Compiled-binary-fastest" tabindex="-1">3. Compiled binary (fastest) <a class="header-anchor" href="#3.-Compiled-binary-fastest" aria-label="Permalink to &quot;3. Compiled binary (fastest) {#3.-Compiled-binary-fastest}&quot;">​</a></h3><p>Compile <code>pt</code> itself to a native executable with juliac. The resulting binary has no Julia-session startup cost:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> app/build_app.jl</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # → ./pt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">./pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> examples/mathx/mathx.jl</span></span></code></pre></div><p>All three accept the same commands and options; the examples below use the bare <code>pt</code> form.</p><h2 id="Commands" tabindex="-1">Commands <a class="header-anchor" href="#Commands" aria-label="Permalink to &quot;Commands {#Commands}&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>pt build  FILE.jl  [OPTIONS]   Compile a CPython extension (.so)</span></span>
<span class="line"><span>pt wheel  FILE.jl  [OPTIONS]   Build a pip-installable wheel</span></span>
<span class="line"><span>pt bench  EXT.so   [OPTIONS]   Measure import + first-call latency</span></span>
<span class="line"><span>pt version                     Print the version string</span></span>
<span class="line"><span>pt help                        Show usage</span></span></code></pre></div><h3 id="pt-build-—-compile-an-extension" tabindex="-1"><code>pt build</code> — compile an extension <a class="header-anchor" href="#pt-build-—-compile-an-extension" aria-label="Permalink to &quot;\`pt build\` — compile an extension {#pt-build-—-compile-an-extension}&quot;">​</a></h3><p>Produces an importable <code>.so</code> (the surrounding environment must provide <code>libjulia</code>, e.g. a Julia install on <code>PATH</code>). Use this during development.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymod.jl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --outdir=build</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymod.jl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --abi3</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # stable-ABI .abi3.so (CPython ≥ 3.11)</span></span></code></pre></div><table tabindex="0"><thead><tr><th style="text-align:right;">Option</th><th style="text-align:right;">Default</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>--outdir=DIR</code></td><td style="text-align:right;">directory of <code>FILE</code></td><td style="text-align:right;">where to write the <code>.so</code></td></tr><tr><td style="text-align:right;"><code>--mod-name=NAME</code></td><td style="text-align:right;">from <code>@pymodule</code>, else filename</td><td style="text-align:right;">Python module name</td></tr><tr><td style="text-align:right;"><code>--trim=safe|unsafe</code></td><td style="text-align:right;"><code>safe</code></td><td style="text-align:right;">juliac trim level</td></tr><tr><td style="text-align:right;"><code>--abi3</code></td><td style="text-align:right;">off</td><td style="text-align:right;">build a stable-ABI extension</td></tr><tr><td style="text-align:right;"><code>--verbose</code></td><td style="text-align:right;">off</td><td style="text-align:right;">print the juliac and <code>cc</code> commands</td></tr></tbody></table><h3 id="pt-wheel-—-build-a-wheel" tabindex="-1"><code>pt wheel</code> — build a wheel <a class="header-anchor" href="#pt-wheel-—-build-a-wheel" aria-label="Permalink to &quot;\`pt wheel\` — build a wheel {#pt-wheel-—-build-a-wheel}&quot;">​</a></h3><p>Produces a pip-installable <code>.whl</code>. By default the wheel bundles the Julia runtime so it imports on a machine with no Julia installed.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymod.jl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --outdir=dist</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version=1.0.0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymod.jl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --runtime=system</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # tiny wheel; needs Julia on target</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymod.jl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --slim</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                     # smaller bundle (~38 MB)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> mymod.jl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --emit-pyproject</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # also write dist/pyproject.toml</span></span></code></pre></div><table tabindex="0"><thead><tr><th style="text-align:right;">Option</th><th style="text-align:right;">Default</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>--outdir=DIR</code></td><td style="text-align:right;"><code>dist</code></td><td style="text-align:right;">output directory</td></tr><tr><td style="text-align:right;"><code>--version=X.Y.Z</code></td><td style="text-align:right;"><code>0.1.0</code></td><td style="text-align:right;">wheel version</td></tr><tr><td style="text-align:right;"><code>--mod-name=NAME</code></td><td style="text-align:right;">from <code>@pymodule</code></td><td style="text-align:right;">Python module name</td></tr><tr><td style="text-align:right;"><code>--trim=safe|unsafe</code></td><td style="text-align:right;"><code>safe</code></td><td style="text-align:right;">juliac trim level</td></tr><tr><td style="text-align:right;"><code>--manylinux=VER|false</code></td><td style="text-align:right;">auto</td><td style="text-align:right;">Linux platform tag (e.g. <code>2.17</code>)</td></tr><tr><td style="text-align:right;"><code>--runtime=bundled|shared|system</code></td><td style="text-align:right;"><code>bundled</code></td><td style="text-align:right;">how the Julia runtime is provided</td></tr><tr><td style="text-align:right;"><code>--slim</code></td><td style="text-align:right;">off</td><td style="text-align:right;">vendor only DT_NEEDED libs (bundled only)</td></tr><tr><td style="text-align:right;"><code>--emit-pyproject</code></td><td style="text-align:right;">off</td><td style="text-align:right;">write a <code>pyproject.toml</code> next to the wheel</td></tr><tr><td style="text-align:right;"><code>--verbose</code></td><td style="text-align:right;">off</td><td style="text-align:right;">print commands</td></tr></tbody></table><p>See <a href="/ParselTongue.jl/dev/guide/building">Building</a> for the meaning of <code>runtime</code>, <code>slim</code>, and <code>emit_pyproject</code>.</p><h3 id="pt-bench-—-measure-startup" tabindex="-1"><code>pt bench</code> — measure startup <a class="header-anchor" href="#pt-bench-—-measure-startup" aria-label="Permalink to &quot;\`pt bench\` — measure startup {#pt-bench-—-measure-startup}&quot;">​</a></h3><p>Reports import and first-call latency for a built extension, averaged over fresh Python processes:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pt</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bench</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build/mathx.cpython-</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.so</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --call=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;mathx.add(1,2)&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --n=5</span></span></code></pre></div><table tabindex="0"><thead><tr><th style="text-align:right;">Option</th><th style="text-align:right;">Default</th><th style="text-align:right;">Meaning</th></tr></thead><tbody><tr><td style="text-align:right;"><code>--call=EXPR</code></td><td style="text-align:right;">none</td><td style="text-align:right;">Python expression to time after import</td></tr><tr><td style="text-align:right;"><code>--n=N</code></td><td style="text-align:right;"><code>5</code></td><td style="text-align:right;">number of fresh-process trials</td></tr></tbody></table><h2 id="Notes" tabindex="-1">Notes <a class="header-anchor" href="#Notes" aria-label="Permalink to &quot;Notes {#Notes}&quot;">​</a></h2><ul><li><p><code>pt</code> covers single-file builds. Multi-module wheels (<a href="/ParselTongue.jl/dev/reference/api#Building"><code>build_multi_wheel</code></a>) take several source files and are currently driven from Julia, not the CLI.</p></li><li><p>Any command run with no positional argument (or <code>--help</code> / <code>-h</code>) prints its usage and exits.</p></li></ul>`,31)])])}const u=e(l,[["render",n]]);export{g as __pageData,u as default};
